// Parse incoming request
const body = $input.item.json;
const { imageBase64, fileName, position, imageIndex, imageTotal } = body;

if (!imageBase64 || !fileName || !position) {
  throw new Error('Missing required fields: imageBase64, fileName, position');
}

return {
  json: {
    imageBase64,
    fileName,
    position: position || 'QB',
    imageIndex: imageIndex || 1,
    imageTotal: imageTotal || 1
  }
};

// Parse and clean the model response
const response = $input.item.json;

let textContent = '';

// Handle different response formats
if (response.choices && response.choices[0]) {
  textContent = response.choices[0].message?.content || '';
} else if (response.content) {
  textContent = response.content;
} else {
  textContent = JSON.stringify(response);
}

// Extract JSON from response
let plays = [];
try {
  // Try direct parse
  plays = JSON.parse(textContent);
} catch {
  // Try to extract JSON array from text
  const start = textContent.indexOf('[');
  if (start !== -1) {
    const end = textContent.lastIndexOf(']') + 1;
    plays = JSON.parse(textContent.substring(start, end));
  }
}

// Ensure we have an array
if (!Array.isArray(plays)) {
  plays = [];
}

// Normalize plays
const normalized = plays
  .filter(p => p && typeof p === 'object')
  .map(p => ({
    col1: String(p.col1 || '').trim(),
    col2: String(p.col2 || '').trim(),
    col3: String(p.col3 || '').trim(),
    col4: String(p.col4 || '').trim()
  }))
  .filter(p => p.col1 || p.col2 || p.col3 || p.col4);

return {
  json: {
    success: true,
    plays: normalized,
    count: normalized.length
  }
};
